INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 0.0, 1, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24001, 0, "リン", "2020/04/30 12:00:00", "あたしだって\nやるときはやるよ！", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 0.0, 1, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24002, 1, "リン", "2020/04/30 12:00:00", "ふぅ…\nこれであたしの仕事は\n終わりだね", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 0.0, 1, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24003, 2, "リン", "2020/04/30 12:00:00", "終わった終わった\n一人でもなんとか\nなるもんだね", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (2, 0.0, 2, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24004, 3, "リン", "2020/04/30 12:00:00", "やったね！\nこれでようやく\nサボれるよ…", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 0.0, 1, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24005, 4, "リン", "2020/04/30 12:00:00", "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (2, 0.0, 2, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24006, 5, "リン", "2020/04/30 12:00:00", "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (2, 0.0, 2, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24007, 6, "リン", "2020/04/30 12:00:00", "あたしも意外と\nやるもんでしょ？", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 0.0, 4, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24008, 7, "リン", "2020/04/30 12:00:00", "疲れた…\nねずみの逃げ足\n速すぎるよ…", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 0.0, 4, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24009, 8, "リン", "2020/04/30 12:00:00", "このままじゃ\nまっひ～に\n叱られちゃうよ", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 0.0, 4, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24010, 9, "リン", "2020/04/30 12:00:00", "まじめに\nやったんだけどな…\n悔しいな～", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 0.0, 4, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24011, 10, "リン", "2020/04/30 12:00:00", "やられた…\nねずみって意外と\nてごわいね", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 0.0, 4, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24012, 11, "リン", "2020/04/30 12:00:00", "おのれ～\nあたしのチーズを\n盗みやがって～！", 0.0);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 1.81, 4, 0.0, 102601, "2030/12/17 14:59:59", 24, 10040, 24013, 12, "リン", "2020/04/30 12:00:00", "疲れた…\nけど、次こそは\n守り抜くよ…", 0.0);
